import { useState, useEffect, useRef, useCallback } from "react";
// ─── AUDIO ────────────────────────────────────────────────────────────────────
const audioCtx = { current: null };

function getAudioCtx() {
  if (!audioCtx.current) audioCtx.current = new (window.AudioContext || window.webkitAudioContext)();
  return audioCtx.current;
}

function playClick() {
  try {
    const ctx = getAudioCtx();
    // Sharp mechanical click - two short bursts
    const buf = ctx.createBuffer(1, ctx.sampleRate * 0.06, ctx.sampleRate);
    const data = buf.getChannelData(0);
    for (let i = 0; i < data.length; i++) {
      const t = i / ctx.sampleRate;
      // Click transient
      data[i] = Math.exp(-t * 180) * (Math.random() * 2 - 1) * 0.8;
      // Add a tiny tonal component for the "tick"
      data[i] += Math.exp(-t * 120) * Math.sin(2 * Math.PI * 1200 * t) * 0.4;
    }
    const src = ctx.createBufferSource();
    src.buffer = buf;
    const gain = ctx.createGain();
    gain.gain.setValueAtTime(0.7, ctx.currentTime);
    src.connect(gain); gain.connect(ctx.destination);
    src.start();
  } catch(e) {}
}

function playPay() {
  try {
    const ctx = getAudioCtx();
    // Reward tone - short ascending two-tone chime
    [[660, 0, 0.12], [880, 0.1, 0.18]].forEach(([freq, delay, dur]) => {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = "sine";
      osc.frequency.setValueAtTime(freq, ctx.currentTime + delay);
      gain.gain.setValueAtTime(0, ctx.currentTime + delay);
      gain.gain.linearRampToValueAtTime(0.4, ctx.currentTime + delay + 0.02);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + delay + dur);
      osc.connect(gain); gain.connect(ctx.destination);
      osc.start(ctx.currentTime + delay);
      osc.stop(ctx.currentTime + delay + dur + 0.05);
    });
  } catch(e) {}
}

function playMiss() {
  try {
    const ctx = getAudioCtx();
    // Low descending tone
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = "sawtooth";
    osc.frequency.setValueAtTime(300, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(120, ctx.currentTime + 0.25);
    gain.gain.setValueAtTime(0.3, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.3);
    osc.connect(gain); gain.connect(ctx.destination);
    osc.start(); osc.stop(ctx.currentTime + 0.35);
  } catch(e) {}
}



